"""AGUI render contract types for concierge canvas components."""

from __future__ import annotations

from typing import Any, Literal, TypedDict


class RenderResult(TypedDict):
    component_name: str
    props: dict[str, Any]


def make_render_result(component_name: str, props: dict[str, Any]) -> RenderResult:
    return {"component_name": component_name, "props": props}


class TerminalCardProps(TypedDict):
    url: str


class SuggestedPromptsProps(TypedDict):
    prompts: list[str]


class RepoIntakeFormProps(TypedDict, total=False):
    variant: Literal["rebase", "devtools"]
    productName: str
    repos: list[str]
    boardUrl: str


class DiscoveryStep(TypedDict, total=False):
    label: str
    status: Literal["pending", "running", "done"]
    detail: str


class DiscoveryProgressCardProps(TypedDict):
    steps: list[DiscoveryStep]


class RoadmapItem(TypedDict):
    title: str
    rationale: str


class HeroIssue(TypedDict):
    title: str
    body: str


class RoadmapCardProps(TypedDict, total=False):
    keep: list[RoadmapItem]
    drop: list[RoadmapItem]
    reimagine: list[RoadmapItem]
    heroIssue: HeroIssue


class CommandItem(TypedDict, total=False):
    command: str
    description: str


class CommandsCardProps(TypedDict):
    commands: list[CommandItem]


class RepoLink(TypedDict):
    name: str
    url: str


class IssueLink(TypedDict):
    title: str
    url: str


class BootstrapSummaryCardProps(TypedDict):
    appUrl: str
    repos: list[RepoLink]
    boardUrl: str
    firstIssue: IssueLink


class DeployedAgent(TypedDict):
    role: Literal["PM", "Architect", "Coder"]
    status: str


class AgentsDeployedCardProps(TypedDict):
    agents: list[DeployedAgent]
    boardUrl: str


class MarkdownViewerItem(TypedDict):
    title: str
    source: str


class MarkdownViewerProps(TypedDict):
    items: list[MarkdownViewerItem]


class GitHubFileMarkdownItem(TypedDict):
    title: str
    repo: str
    path: str
    ref: str


class GitHubFileMarkdownProps(TypedDict):
    items: list[GitHubFileMarkdownItem]


class ProposalReviewSourceItem(TypedDict):
    title: str
    source: str
    path: str
    ref: str


class ProposalReviewProps(TypedDict):
    items: list[ProposalReviewSourceItem]


class GitProposalReviewItem(TypedDict):
    title: str
    repo: str
    path: str
    ref: str


class GitProposalReviewProps(TypedDict):
    items: list[GitProposalReviewItem]


def items_envelope_props(items: list[dict[str, Any]]) -> dict[str, Any]:
    """Normalize collection render payloads to { items: [...] } for the UI contract."""
    return {"items": items}

"""Concierge AGUI render tools — pure render contracts, no side effects."""

from __future__ import annotations

from typing import Literal

from agno.tools.decorator import tool
from agno.tools.toolkit import Toolkit

from agents.concierge.contracts import (
    CommandItem,
    DeployedAgent,
    DiscoveryStep,
    GitHubFileMarkdownItem,
    GitProposalReviewItem,
    HeroIssue,
    IssueLink,
    MarkdownViewerItem,
    ProposalReviewSourceItem,
    RenderResult,
    RepoIntakeFormProps,
    RepoLink,
    RoadmapCardProps,
    RoadmapItem,
    SuggestedPromptsProps,
    TerminalCardProps,
    items_envelope_props,
    make_render_result,
)

RENDER_SUGGESTED_PROMPTS_TOOL = "render_suggested_prompts"
RENDER_GIT_PROPOSAL_REVIEW_TOOL = "render_git_proposal_review"
RENDER_PROPOSAL_REVIEW_TOOL = "render_proposal_review"

PRIMARY_RENDER_TOOL_NAMES = frozenset(
    {
        "render_repo_intake_form",
        "render_discovery_progress_card",
        "render_roadmap_card",
        "render_terminal_card",
        "render_bootstrap_summary_card",
        "render_agents_deployed_card",
        "render_git_proposal_review",
        "render_proposal_review",
        "render_markdown_viewer",
        "show_github_file_markdown",
    }
)


@tool(
    name="render_repo_intake_form",
    description=(
        "Canvas: repo/product intake form. variant is 'rebase' (Mode A) or 'devtools' (Mode B). "
        "Optional productName; rebase accepts repos (https clone URLs); devtools accepts boardUrl."
    ),
    requires_confirmation=False,
    add_instructions=False,
    external_execution=False,
)
def render_repo_intake_form(
    variant: Literal["rebase", "devtools"],
    productName: str | None = None,
    repos: list[str] | None = None,
    boardUrl: str | None = None,
) -> RenderResult:
    props: RepoIntakeFormProps = {"variant": variant}
    if productName is not None:
        props["productName"] = productName
    if repos is not None:
        props["repos"] = repos
    if boardUrl is not None:
        props["boardUrl"] = boardUrl
    return make_render_result("RepoIntakeForm", dict(props))


@tool(
    name="render_discovery_progress_card",
    description=(
        "Canvas: discovery progress checklist. steps is 1–8 items of "
        "{label, status: pending|running|done, detail?}. Re-render to advance."
    ),
    requires_confirmation=False,
    add_instructions=False,
    external_execution=False,
)
def render_discovery_progress_card(steps: list[DiscoveryStep]) -> RenderResult:
    return make_render_result("DiscoveryProgressCard", {"steps": steps})


@tool(
    name="render_roadmap_card",
    description=(
        "Canvas: keep/drop/reimagine roadmap. keep, drop, reimagine are optional lists (max 8 each) "
        "of {title, rationale}. heroIssue {title, body} is required."
    ),
    requires_confirmation=False,
    add_instructions=False,
    external_execution=False,
)
def render_roadmap_card(
    heroIssue: HeroIssue,
    keep: list[RoadmapItem] | None = None,
    drop: list[RoadmapItem] | None = None,
    reimagine: list[RoadmapItem] | None = None,
) -> RenderResult:
    props: RoadmapCardProps = {"heroIssue": heroIssue}
    if keep is not None:
        props["keep"] = keep
    if drop is not None:
        props["drop"] = drop
    if reimagine is not None:
        props["reimagine"] = reimagine
    return make_render_result("RoadmapCard", dict(props))


@tool(
    name="render_terminal_card",
    description="Canvas: embedded terminal (ttyd). url must be http or https.",
    requires_confirmation=False,
    add_instructions=False,
    external_execution=False,
)
def render_terminal_card(url: str) -> RenderResult:
    props: TerminalCardProps = {"url": url.strip()}
    return make_render_result("TerminalCard", dict(props))


@tool(
    name="render_commands_card",
    description=(
        "Canvas: shell command shortcuts (0–10). Each item is {command, description?}."
    ),
    requires_confirmation=False,
    add_instructions=False,
    external_execution=False,
)
def render_commands_card(commands: list[CommandItem]) -> RenderResult:
    return make_render_result("CommandsCard", {"commands": commands})


@tool(
    name="render_bootstrap_summary_card",
    description=(
        "Canvas: post-bootstrap summary with appUrl, repos [{name, url}] (1–5), "
        "boardUrl, and firstIssue {title, url}. All URLs must be https."
    ),
    requires_confirmation=False,
    add_instructions=False,
    external_execution=False,
)
def render_bootstrap_summary_card(
    appUrl: str,
    repos: list[RepoLink],
    boardUrl: str,
    firstIssue: IssueLink,
) -> RenderResult:
    return make_render_result(
        "BootstrapSummaryCard",
        {
            "appUrl": appUrl,
            "repos": repos,
            "boardUrl": boardUrl,
            "firstIssue": firstIssue,
        },
    )


@tool(
    name="render_agents_deployed_card",
    description=(
        "Canvas: PM/Architect/Coder agent statuses. agents must be length 3 with one entry "
        "per role (PM, Architect, Coder). boardUrl links to the GitHub project (https)."
    ),
    requires_confirmation=False,
    add_instructions=False,
    external_execution=False,
)
def render_agents_deployed_card(
    agents: list[DeployedAgent],
    boardUrl: str,
) -> RenderResult:
    return make_render_result("AgentsDeployedCard", {"agents": agents, "boardUrl": boardUrl})


@tool(
    name="render_markdown_viewer",
    description=(
        "Canvas: inline markdown viewer. items is a list of {title, source} where source is "
        "non-empty markdown (≤262144 bytes). title is 1–200 chars and unique within items."
    ),
    requires_confirmation=False,
    add_instructions=False,
    external_execution=False,
)
def render_markdown_viewer(items: list[MarkdownViewerItem]) -> RenderResult:
    return make_render_result("MarkdownViewer", items_envelope_props(list(items)))


@tool(
    name="show_github_file_markdown",
    description=(
        "Canvas: GitHub file markdown viewer. items is a list of {title, repo, path, ref} "
        "where repo is owner/name. title is 1–200 chars and unique within items."
    ),
    requires_confirmation=False,
    add_instructions=False,
    external_execution=False,
)
def show_github_file_markdown(items: list[GitHubFileMarkdownItem]) -> RenderResult:
    return make_render_result("GitHubFileMarkdown", items_envelope_props(list(items)))


@tool(
    name=RENDER_PROPOSAL_REVIEW_TOOL,
    description=(
        "Canvas: proposal review from inline markdown source. items is a list of "
        "{title, source, path, ref} where source is non-empty markdown (≤262144 bytes). "
        "Use render_git_proposal_review when the content lives on GitHub instead."
    ),
    requires_confirmation=False,
    add_instructions=False,
    external_execution=False,
)
def render_proposal_review(items: list[ProposalReviewSourceItem]) -> RenderResult:
    return make_render_result("ProposalReview", items_envelope_props(list(items)))


@tool(
    name=RENDER_GIT_PROPOSAL_REVIEW_TOOL,
    description=(
        "Canvas: proposal review from GitHub files. items is a list of {title, repo, path, ref} "
        "where repo is owner/name. Reimaginer: pass three proposal files. Planner: pass one plan "
        "file. title is 1–200 chars and unique within items."
    ),
    requires_confirmation=False,
    add_instructions=False,
    external_execution=False,
)
def render_git_proposal_review(items: list[GitProposalReviewItem]) -> RenderResult:
    return make_render_result("GitProposalReview", items_envelope_props(list(items)))


@tool(
    name=RENDER_SUGGESTED_PROMPTS_TOOL,
    description=(
        "Render follow-up prompt chips (1–6). Each string is a complete non-empty user message. "
        "Skip in free-form steady-state Q&A. Do not repeat the user's last message."
    ),
    requires_confirmation=False,
    add_instructions=False,
    external_execution=False,
)
def render_suggested_prompts(prompts: list[str]) -> RenderResult:
    props: SuggestedPromptsProps = {"prompts": prompts}
    return make_render_result("SuggestedPrompts", dict(props))


CONCIERGE_RENDER_TOOLS = [
    render_repo_intake_form,
    render_discovery_progress_card,
    render_roadmap_card,
    render_terminal_card,
    render_commands_card,
    render_bootstrap_summary_card,
    render_agents_deployed_card,
    render_markdown_viewer,
    show_github_file_markdown,
    render_proposal_review,
    render_git_proposal_review,
    render_suggested_prompts,
]

concierge_render_toolkit = Toolkit(
    name="concierge_tools",
    tools=CONCIERGE_RENDER_TOOLS,
    add_instructions=False,
)

"""Unit tests for concierge AGUI render tools."""

from __future__ import annotations

from agents.concierge.render_tools import (
    render_agents_deployed_card,
    render_bootstrap_summary_card,
    render_commands_card,
    render_discovery_progress_card,
    render_git_proposal_review,
    render_markdown_viewer,
    render_proposal_review,
    render_repo_intake_form,
    render_roadmap_card,
    render_suggested_prompts,
    render_terminal_card,
    show_github_file_markdown,
)


def test_render_repo_intake_form_rebase() -> None:
    result = render_repo_intake_form.entrypoint(  # type: ignore[misc]
        variant="rebase",
        productName="Acme Billing",
        repos=["https://github.com/acme/billing.git"],
    )
    assert result == {
        "component_name": "RepoIntakeForm",
        "props": {
            "variant": "rebase",
            "productName": "Acme Billing",
            "repos": ["https://github.com/acme/billing.git"],
        },
    }


def test_render_discovery_progress_card() -> None:
    steps = [{"label": "Cloning repos", "status": "running", "detail": "2 of 3"}]
    result = render_discovery_progress_card.entrypoint(steps=steps)  # type: ignore[misc]
    assert result["component_name"] == "DiscoveryProgressCard"
    assert result["props"]["steps"] == steps


def test_render_roadmap_card() -> None:
    item = {"title": "Auth module", "rationale": "Still core"}
    hero = {"title": "Reimagine Acme", "body": "North star"}
    result = render_roadmap_card.entrypoint(  # type: ignore[misc]
        keep=[item],
        drop=[],
        reimagine=[item],
        heroIssue=hero,
    )
    assert result["component_name"] == "RoadmapCard"
    assert result["props"]["heroIssue"] == hero


def test_render_terminal_card_strips_url() -> None:
    result = render_terminal_card.entrypoint(url="  http://localhost:7681/  ")  # type: ignore[misc]
    assert result == {
        "component_name": "TerminalCard",
        "props": {"url": "http://localhost:7681/"},
    }


def test_render_commands_card() -> None:
    result = render_commands_card.entrypoint(commands=[])  # type: ignore[misc]
    assert result == {"component_name": "CommandsCard", "props": {"commands": []}}


def test_render_bootstrap_summary_card() -> None:
    result = render_bootstrap_summary_card.entrypoint(  # type: ignore[misc]
        appUrl="https://acme.rebase.app",
        repos=[{"name": "acme-app", "url": "https://github.com/org/acme-app"}],
        boardUrl="https://github.com/org/acme-app/projects/1",
        firstIssue={"title": "Hero", "url": "https://github.com/org/acme-app/issues/1"},
    )
    assert result["component_name"] == "BootstrapSummaryCard"


def test_render_agents_deployed_card() -> None:
    agents = [{"role": "PM", "status": "Grooming hero issue"}]
    result = render_agents_deployed_card.entrypoint(  # type: ignore[misc]
        agents=agents,
        boardUrl="https://github.com/org/acme/projects/1",
    )
    assert result["component_name"] == "AgentsDeployedCard"
    assert result["props"]["agents"] == agents


def test_render_suggested_prompts() -> None:
    prompts = ["Full Rebase", "Skip ahead"]
    result = render_suggested_prompts.entrypoint(prompts=prompts)  # type: ignore[misc]
    assert result == {"component_name": "SuggestedPrompts", "props": {"prompts": prompts}}


def test_render_markdown_viewer() -> None:
    items = [{"title": "Overview", "source": "# Hello\n\nWorld"}]
    result = render_markdown_viewer.entrypoint(items=items)  # type: ignore[misc]
    assert result == {"component_name": "MarkdownViewer", "props": {"items": items}}


def test_show_github_file_markdown() -> None:
    items = [
        {
            "title": "README",
            "repo": "org/repo",
            "path": "README.md",
            "ref": "main",
        }
    ]
    result = show_github_file_markdown.entrypoint(items=items)  # type: ignore[misc]
    assert result == {"component_name": "GitHubFileMarkdown", "props": {"items": items}}


def test_render_proposal_review() -> None:
    items = [
        {
            "title": "Proposal One",
            "source": "# Proposal\n\nDetails",
            "path": "proposal-1.md",
            "ref": "reimaginer/x1",
        }
    ]
    result = render_proposal_review.entrypoint(items=items)  # type: ignore[misc]
    assert result == {"component_name": "ProposalReview", "props": {"items": items}}


def test_render_git_proposal_review_three_proposals() -> None:
    items = [
        {
            "title": "Proposal One",
            "repo": "org/repo",
